// AdOff — Review Poller (n8n Code node, runOnceForAllItems)
// Sorgenti: Firefox AMO (recensioni complete) + Edge (delta aggregato). CWS testi = richiede headless (non qui).
// Stato (dedup) in workflow static data. Telegram: thread 24 (Recensioni).
// Token/chat: da $env (TELEGRAM_BOT_TOKEN, TELEGRAM_CHAT_ID in /opt/n8n/.env). Se $env è bloccato, sostituisci con valori o credenziale.

const AMO_SLUG = "adoff";
const EDGE_CRX = "oddekkkjecbnogahoielolemebjlmclk";
const THREAD = 24;
const stars = n => "★".repeat(Math.max(0, Math.min(5, n | 0))) + "☆".repeat(5 - Math.max(0, Math.min(5, n | 0)));

const token = $env.TELEGRAM_BOT_TOKEN;
const chat = $env.TELEGRAM_CHAT_ID;
const sd = $getWorkflowStaticData("global");
if (!Array.isArray(sd.amoSeen)) sd.amoSeen = [];
if (sd.edgeCount === undefined) sd.edgeCount = null;

const messages = [];

// Firefox AMO — recensioni complete
try {
  const d = await this.helpers.httpRequest({ url: `https://addons.mozilla.org/api/v5/ratings/rating/?addon=${AMO_SLUG}&page_size=25`, json: true });
  for (const r of (d.results || []).reverse()) {
    const id = "amo:" + r.id;
    if (sd.amoSeen.includes(id)) continue;
    sd.amoSeen.push(id);
    const body = (r.body || "").trim();
    messages.push(`🦊 <b>Firefox AMO</b> ${stars(r.score)} (${r.score}/5)\n👤 ${(r.user && r.user.name) || "anon"}\n${body ? body.slice(0, 600) : "<i>(senza testo)</i>"}`);
  }
} catch (e) { messages.push("⚠️ AMO poll error: " + e.message); }

// Edge — solo aggregato (delta numero recensioni)
try {
  const d = await this.helpers.httpRequest({ url: `https://microsoftedge.microsoft.com/addons/getproductdetailsbycrxid/${EDGE_CRX}`, json: true });
  const count = d.ratingCount || 0, avg = d.averageRating || 0;
  if (sd.edgeCount !== null && count > sd.edgeCount) {
    messages.push(`🔷 <b>Edge Add-ons</b>: ${count - sd.edgeCount} nuova/e recensione/i (totale ${count}, media ${avg.toFixed(1)}/5).\n<i>Edge non espone i testi via API — apri lo store.</i>`);
  }
  sd.edgeCount = count;
} catch (e) { messages.push("⚠️ Edge poll error: " + e.message); }

// Scraper Playwright (testi CWS/Edge) — servizio HTTP locale su leobox
const SCRAPER_URL = $env.ADOFF_SCRAPER_URL || "http://100.71.178.53:8788/poll";
try {
  const s = await this.helpers.httpRequest({ url: SCRAPER_URL, json: true, timeout: 180000 });
  for (const r of (s.cws?.newReviews || [])) {
    const body = (r.body || "").trim();
    messages.push(`🟢 <b>Chrome Web Store</b> ${stars(r.score)} (${r.score}/5)\n👤 ${r.author || "anon"}\n${body ? body.slice(0, 600) : "<i>(senza testo)</i>"}`);
  }
  for (const r of (s.edge?.newReviews || [])) {
    const body = (r.body || "").trim();
    messages.push(`🔷 <b>Edge Add-ons</b> ${stars(r.score)} (${r.score}/5)\n👤 ${r.author || "anon"}\n${body ? body.slice(0, 600) : "<i>(senza testo)</i>"}`);
  }
} catch (e) { messages.push("⚠️ Scraper poll error: " + e.message); }

if (sd.amoSeen.length > 500) sd.amoSeen = sd.amoSeen.slice(-500);

// Invio Telegram (thread 24)
let posted = 0;
for (const text of messages) {
  try {
    await this.helpers.httpRequest({
      method: "POST",
      url: `https://api.telegram.org/bot${token}/sendMessage`,
      body: { chat_id: chat, message_thread_id: THREAD, text, parse_mode: "HTML", disable_web_page_preview: true },
      json: true,
    });
    posted++;
  } catch (e) { /* skip */ }
}

return [{ json: { checked: true, newReviews: messages.length, posted, edgeCount: sd.edgeCount, amoSeen: sd.amoSeen.length } }];
